INSERT INTO `status_group` VALUES (1,'active','Activo','El ticket sigue en trabajo, revisión, testing, backlog, espera, triage u otra etapa no final.',0,0,1,1),(2,'resolution','Resolución/cierre','El ticket llegó a un cierre o resolución usable como punto de corte temporal.',1,1,0,1),(3,'non_fix_resolution','Cierre no asociado a corrección','El ticket fue cerrado por una razón no asociada necesariamente a corrección real, como inválido, duplicado o no se corregirá.',1,0,0,1),(4,'explicit_reopen','Reapertura explícita','Estado explícito de reapertura, por ejemplo Reopened.',0,0,1,1),(5,'unclear','Dudoso','Estado ambiguo o no clasificado. No se usa para definir el target en la primera versión.',0,0,0,0),(6,'validation','Validación/revisión/testing','El ticket se encuentra en revisión, QA, testing o espera de validación. No es cierre definitivo, pero puede funcionar como punto de corte para predecir retorno a trabajo activo.',0,0,0,1);
